import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int[] a = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = scanner.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < n; i++) {
                sum += a[i];
                if (sum >= n) {
                    System.out.println(i + 1);
                    break;
                }
            }
        }
    }
}

