const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let n;
let a;
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else if (i % 2 === 1) {
        n = parseInt(line);
    } else {
        a = line.split(' ').map(num => parseInt(num));
        let sum = 0;
        for (let j = 0; j < n; j++) {
            sum += a[j];
            if (sum >= n) {
                console.log(j + 1);
                break;
            }
        }
    }
    i++;
    if (i >= t * 2 + 1) {
        readline.close();
    }
});
